    "id": "migraine",
    "disease_en": "Migraine",
    "disease_ta": "ஒற்றைத் தலைவலி (மைக்ரேன்)",
    "name_en": "Peppermint Steam",
    "name_ta": "மிளகுக்கீரை நீராவி",
    "category": "pain_relief",
