    "id": "adhd-support",
    "disease_en": "ADHD Support",
    "disease_ta": "ஏடிஹெச்டி ஆதரவு",
    "name_en": "Brahmi Almond Milk",
    "name_ta": "பிராமி பாதாம் பால்",
    "category": "mental_neurological",
